import React, { useState, useEffect } from 'react';
import { Menu, X, Phone } from 'lucide-react';
import { WHATSAPP_URL } from '../constants';

const Navbar: React.FC = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <nav className={`fixed w-full z-50 transition-all duration-500 ${isScrolled ? 'bg-black/90 backdrop-blur-md py-4' : 'bg-transparent py-6'}`}>
      <div className="container mx-auto px-6 flex justify-between items-center">
        <div className="flex items-center space-x-2">
          <div className="w-10 h-10 bg-gold-gradient rounded-full flex items-center justify-center shadow-[0_0_15px_rgba(212,175,55,0.5)]">
            <span className="text-black font-bold text-xl font-gold">A</span>
          </div>
          <span className="text-xl font-bold font-gold tracking-widest text-white">
            MF <span className="text-gold">AURUM</span> LEGACY
          </span>
        </div>

        {/* Desktop Links */}
        <div className="hidden md:flex items-center space-x-8 text-sm font-semibold tracking-wide">
          <a href="#home" className="hover:text-gold transition-colors">INÍCIO</a>
          <a href="#about" className="hover:text-gold transition-colors">O LEGADO</a>
          <a href="#services" className="hover:text-gold transition-colors">SERVIÇOS</a>
          <a href="#gallery" className="hover:text-gold transition-colors">GALERIA</a>
          <a href={WHATSAPP_URL} target="_blank" className="flex items-center bg-gold-gradient text-black px-6 py-2 rounded-full hover:scale-105 transition-transform">
            <Phone className="w-4 h-4 mr-2" />
            AGENDAR
          </a>
        </div>

        {/* Mobile Toggle */}
        <button className="md:hidden text-white" onClick={() => setIsMenuOpen(!isMenuOpen)}>
          {isMenuOpen ? <X size={28} /> : <Menu size={28} />}
        </button>
      </div>

      {/* Mobile Menu */}
      {isMenuOpen && (
        <div className="md:hidden absolute top-full left-0 w-full bg-black border-t border-gold/20 py-6 px-6 space-y-4 animate-fade-in-down">
          <a href="#home" onClick={() => setIsMenuOpen(false)} className="block text-lg hover:text-gold transition-colors">Início</a>
          <a href="#about" onClick={() => setIsMenuOpen(false)} className="block text-lg hover:text-gold transition-colors">O Legado</a>
          <a href="#services" onClick={() => setIsMenuOpen(false)} className="block text-lg hover:text-gold transition-colors">Serviços</a>
          <a href="#gallery" onClick={() => setIsMenuOpen(false)} className="block text-lg hover:text-gold transition-colors">Galeria</a>
          <a href={WHATSAPP_URL} target="_blank" className="block text-center bg-gold-gradient text-black px-6 py-3 rounded-md font-bold">
            Agendar Via WhatsApp
          </a>
        </div>
      )}
    </nav>
  );
};

