import React, { useState, useMemo } from 'react';
import { Quote, Star, MessageSquarePlus, ChevronDown, ChevronUp, User } from 'lucide-react';
import { TESTIMONIALS } from '../constants';
import { Testimonial } from '../types';

const Testimonials: React.FC = () => {
  const [userTestimonials, setUserTestimonials] = useState<Testimonial[]>([]);
  const [isExpanded, setIsExpanded] = useState(false);
  const [activeFilter, setActiveFilter] = useState<number | null>(null);

  // Form State
  const [formData, setFormData] = useState({
    name: '',
    car: '',
    text: '',
    rating: 5
  });
  const [showForm, setShowForm] = useState(false);

  const allTestimonials = useMemo(() => {
    return [...userTestimonials, ...TESTIMONIALS];
  }, [userTestimonials]);

  const filteredTestimonials = useMemo(() => {
    let list = activeFilter 
      ? allTestimonials.filter(t => t.rating === activeFilter)
      : allTestimonials;

    return isExpanded ? list : list.slice(0, 3);
  }, [allTestimonials, activeFilter, isExpanded]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.car || !formData.text) return;

    const newComment: Testimonial = {
      id: Date.now(),
      name: formData.name,
      role: formData.car,
      text: formData.text,
      rating: formData.rating
    };

    setUserTestimonials([newComment, ...userTestimonials]);
    setFormData({ name: '', car: '', text: '', rating: 5 });
    setShowForm(false);
    alert("Obrigado pelo seu feedback! Seu depoimento foi adicionado.");
  };

  const StarRating = ({ rating, interactive = false, onRate }: { rating: number, interactive?: boolean, onRate?: (r: number) => void }) => (
    <div className="flex gap-1">
      {[1, 2, 3, 4, 5].map((s) => (
        <Star 
          key={s} 
          size={14} 
          onClick={() => interactive && onRate?.(s)}
          className={`${s <= rating ? 'text-gold fill-gold' : 'text-gray-600'} ${interactive ? 'cursor-pointer hover:scale-125 transition-transform' : ''}`} 
        />
      ))}
    </div>
  );

  return (
    <section className="py-24 bg-[#0a0a0a]">
      <div className="container mx-auto px-6">
        <div className="text-center mb-16">
          <h3 className="text-gold font-bold tracking-[0.2em] mb-4 uppercase text-xs">Experiência do Cliente</h3>
          <h2 className="text-3xl md:text-5xl font-bold font-gold mb-4 italic">Quem já viveu o Legado</h2>
          <div className="w-24 h-1 bg-gold-gradient mx-auto mb-12"></div>

          {/* Filtros com caixas brancas e letras pretas */}
          <div className="flex flex-wrap justify-center items-center gap-4 mb-12">
            <button 
              onClick={() => setActiveFilter(null)}
              className={`px-8 py-3 text-[11px] font-bold tracking-[0.2em] uppercase transition-all duration-300 shadow-xl ${activeFilter === null ? 'bg-gold text-black' : 'bg-white text-black hover:bg-gray-200'}`}
            >
              Todos
            </button>
            {[5, 4, 3, 2, 1].map(star => (
              <button 
                key={star}
                onClick={() => setActiveFilter(star)}
                className={`flex items-center gap-3 px-8 py-3 text-[11px] font-bold tracking-[0.2em] uppercase transition-all duration-300 shadow-xl ${activeFilter === star ? 'bg-gold text-black' : 'bg-white text-black hover:bg-gray-200'}`}
              >
                {star} <Star size={12} className="fill-current" />
              </button>
            ))}
          </div>
        </div>

        {/* Action Buttons */}
        <div className="flex justify-center mb-12">
          <button 
            onClick={() => setShowForm(!showForm)}
            className="flex items-center gap-3 bg-white/5 border border-gold/30 px-8 py-4 text-gold font-bold text-[11px] tracking-widest uppercase hover:bg-gold/10 transition-all"
          >
            <MessageSquarePlus size={18} />
            {showForm ? 'Fechar Formulário' : 'Adicionar sua Experiência'}
          </button>
        </div>

        {/* New Comment Form */}
        {showForm && (
          <div className="max-w-2xl mx-auto mb-16 p-8 bg-[#111] border border-gold/20 animate-in fade-in slide-in-from-top-4">
            <h4 className="text-white font-gold text-xl mb-6 text-center uppercase tracking-widest">Seu Feedback</h4>
            <form onSubmit={handleSubmit} className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <input 
                  type="text" 
                  placeholder="Seu Nome" 
                  className="bg-black border border-white/10 p-4 text-white outline-none focus:border-gold transition-colors text-sm"
                  value={formData.name}
                  onChange={e => setFormData({...formData, name: e.target.value})}
                  required
                />
                <input 
                  type="text" 
                  placeholder="Modelo do Veículo" 
                  className="bg-black border border-white/10 p-4 text-white outline-none focus:border-gold transition-colors text-sm"
                  value={formData.car}
                  onChange={e => setFormData({...formData, car: e.target.value})}
                  required
                />
              </div>
              <div className="flex flex-col items-center gap-3 bg-black/40 p-4 border border-white/5">
                <span className="text-xs text-gray-500 uppercase tracking-widest">Sua Avaliação</span>
                <StarRating rating={formData.rating} interactive onRate={(r) => setFormData({...formData, rating: r})} />
              </div>
              <textarea 
                placeholder="Conte-nos sua experiência..." 
                rows={4}
                className="w-full bg-black border border-white/10 p-4 text-white outline-none focus:border-gold transition-colors text-sm resize-none"
                value={formData.text}
                onChange={e => setFormData({...formData, text: e.target.value})}
                required
              ></textarea>
              <button 
                type="submit"
                className="w-full bg-gold-gradient text-black font-bold py-4 text-xs tracking-[0.3em] uppercase hover:brightness-110 transition-all"
              >
                Publicar Comentário
              </button>
            </form>
          </div>
        )}

        {/* Testimonials Grid */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mb-16">
          {filteredTestimonials.length > 0 ? filteredTestimonials.map((t) => (
            <div key={t.id} className="p-8 bg-[#111] border border-white/5 relative group hover:border-gold/20 transition-all duration-500 flex flex-col h-full">
              <Quote className="absolute top-4 right-4 text-gold/5 group-hover:text-gold/20 transition-colors" size={48} />

              <div className="mb-4">
                <StarRating rating={t.rating} />
              </div>

              <p className="text-gray-400 italic leading-relaxed mb-8 flex-grow">"{t.text}"</p>

              <div className="flex items-center gap-4 mt-auto pt-6 border-t border-white/5">
                {t.avatar ? (
                  <img src={t.avatar} alt={t.name} className="w-12 h-12 rounded-full border border-gold/40 object-cover" />
                ) : (
                  <div className="w-12 h-12 rounded-full border border-gold/40 flex items-center justify-center bg-black">
                    <User size={20} className="text-gold/60" />
                  </div>
                )}
                <div>
                  <h4 className="font-bold text-white text-sm">{t.name}</h4>
                  <p className="text-gold text-[10px] tracking-widest uppercase">{t.role}</p>
                </div>
              </div>
            </div>
          )) : (
            <div className="col-span-full py-20 text-center border border-white/5 border-dashed">
              <p className="text-gray-500 font-gold italic uppercase tracking-widest">Nenhum depoimento com {activeFilter} estrelas.</p>
            </div>
          )}
        </div>

        {/* View More Button */}
        {allTestimonials.length > 3 && (
          <div className="flex justify-center">
            <button 
              onClick={() => setIsExpanded(!isExpanded)}
              className="group flex flex-col items-center gap-2 text-gold text-[10px] font-bold tracking-[0.4em] uppercase transition-all"
            >
              <span>{isExpanded ? 'Ver Menos' : 'Ver mais experiências'}</span>
              <div className="mt-2 text-gold/40 group-hover:text-gold transition-colors">
                {isExpanded ? <ChevronUp size={24} /> : <ChevronDown size={24} />}
              </div>
            </button>
          </div>
        )}
      </div>
    </section>
  );
};

