const Gallery: React.FC = () => {
  const [isExpanded, setIsExpanded] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const [currentPage, setCurrentPage] = useState(0);

  const items = [
    // Página 1 - Grid 3x3 (ou o que houver disponível)
    { type: 'video', url: 'https://cdn.pixabay.com/video/2021/04/12/70860-536976694_tiny.mp4', poster: 'https://images.unsplash.com/photo-1549317661-bd32c8ce0db2?q=80&w=800', title: 'Vitrificação Full' },
    { type: 'photo', url: 'https://images.unsplash.com/photo-1620714223084-8fcacc6dfd8d?q=80&w=800', title: 'Correção de Pintura' },
    { type: 'video', url: 'https://cdn.pixabay.com/video/2020/09/21/50634-463284000_tiny.mp4', poster: 'https://images.unsplash.com/photo-1618843479313-40f8afb4b4d8?q=80&w=800', title: 'Hidratação de Couro' },
