    { type: 'video', url: 'https://cdn.pixabay.com/video/2023/10/24/186358-877960330_tiny.mp4', poster: 'https://images.unsplash.com/photo-1580273916550-e323be2ae537?q=80&w=800', title: 'Entrega Técnica' },
    { type: 'photo', url: 'https://images.unsplash.com/photo-1494976388531-d1058494cdd8?q=80&w=800', title: 'Legacy Experience' },
    { type: 'photo', url: 'https://images.unsplash.com/photo-1503376780353-7e6692767b70?q=80&w=800', title: 'Proteção de Pintura' },
    { type: 'video', url: 'https://cdn.pixabay.com/video/2022/01/26/105553-669567406_tiny.mp4', poster: 'https://images.unsplash.com/photo-1603584173870-7f39466548a3?q=80&w=800', title: 'Lavagem Detalhada' },
    { type: 'photo', url: 'https://images.unsplash.com/photo-1552519507-da3b142c6e3d?q=80&w=800', title: 'Reflexos Aurum' },

    // Página 2 (Simulação para o "Arraste")
    { type: 'photo', url: 'https://images.unsplash.com/photo-1492144534655-ae79c964c9d7?q=80&w=800', title: 'Acabamento Premium' },
    { type: 'video', url: 'https://cdn.pixabay.com/video/2021/02/10/64648-511871234_tiny.mp4', poster: 'https://images.unsplash.com/photo-1493238792000-8113da705763?q=80&w=800', title: 'Motor Detail' },
    { type: 'photo', url: 'https://images.unsplash.com/photo-1553440569-bcc63803a83d?q=80&w=800', title: 'Padrão Ouro' },
  ];

  // Agrupa itens em páginas de 9 (3x3)
  const itemsPerPage = 9;
  const pages = [];
  for (let i = 0; i < items.length; i += itemsPerPage) {
    pages.push(items.slice(i, i + itemsPerPage));
  }

  const handleScroll = () => {
    if (scrollRef.current) {
      const scrollLeft = scrollRef.current.scrollLeft;
      const width = scrollRef.current.offsetWidth;
      const newPage = Math.round(scrollLeft / width);
      setCurrentPage(newPage);
    }
  };

  const scrollToPage = (pageIdx: number) => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({
        left: scrollRef.current.offsetWidth * pageIdx,
        behavior: 'smooth'
      });
    }
  };

  return (
    <section id="gallery" className="py-24 bg-[#050505] overflow-hidden">
      <div className="container mx-auto px-6 text-center mb-16">
        <h3 className="text-gold font-bold tracking-[0.4em] mb-4 uppercase text-[10px]">Portfólio</h3>
        <h2 className="text-4xl md:text-6xl font-bold font-gold mb-6 text-white uppercase tracking-tight">Galeria de Resultados</h2>
        <div className="w-24 h-[2px] bg-gold-gradient mx-auto"></div>
      </div>

      {!isExpanded ? (
        /* VISTA INICIAL: Apenas 3 itens */
        <div className="container mx-auto px-6">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            {items.slice(0, 3).map((item, idx) => (
              <GalleryItem key={idx} item={item} />
            ))}
          </div>
          <div className="mt-12 text-center">
            <button 
              onClick={() => setIsExpanded(true)}
              className="px-12 py-5 border border-gold/30 text-gold font-bold text-[11px] tracking-[0.4em] uppercase hover:bg-gold hover:text-black transition-all"
            >
              Ver Mais Resultados
            </button>
          </div>
        </div>
      ) : (
        /* VISTA EXPANDIDA: Slider de Grids 3x3 */
        <div className="relative">
          {/* Scroll Container */}
          <div 
            ref={scrollRef}
            onScroll={handleScroll}
            className="flex overflow-x-auto snap-x snap-mandatory hide-scrollbar cursor-grab active:cursor-grabbing"
            style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}
          >
            {pages.map((pageItems, pageIdx) => (
              <div 
                key={pageIdx} 
                className="min-w-full snap-start px-6"
              >
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4 max-w-7xl mx-auto">
                  {/* Grid 3x3 dentro de cada página */}
                  {pageItems.map((item, idx) => (
                    <div key={idx} className="h-[300px] md:h-[400px]">
                      <GalleryItem item={item} />
                    </div>
                  ))}
                </div>
              </div>
            ))}
          </div>

          {/* Paginação (Dots) */}
          <div className="flex justify-center items-center gap-3 mt-12">
            {pages.map((_, idx) => (
              <button
                key={idx}
                onClick={() => scrollToPage(idx)}
                className={`w-2 h-2 rounded-full transition-all duration-300 ${currentPage === idx ? 'bg-gold w-8' : 'bg-white/20 hover:bg-white/40'}`}
              />
            ))}
          </div>

          {/* Botão para Retornar */}
          <div className="mt-12 text-center">
            <button 
              onClick={() => {
                setIsExpanded(false);
                window.location.href = '#gallery';
              }}
              className="text-gray-500 hover:text-white text-[10px] font-bold tracking-[0.3em] uppercase transition-colors"
            >
              Recolher Galeria
            </button>
          </div>

          {/* Instrução de Arraste sutil */}
          <div className="absolute top-1/2 left-4 -translate-y-1/2 opacity-0 lg:opacity-100 pointer-events-none text-white/10 group">
             <ChevronLeft size={60} />
          </div>
          <div className="absolute top-1/2 right-4 -translate-y-1/2 opacity-0 lg:opacity-100 pointer-events-none text-white/10 group">
             <ChevronRight size={60} />
          </div>
        </div>
      )}

      <div className="mt-16 text-center">
        <a 
          href={`https://instagram.com/${INSTAGRAM.replace('@', '')}`}
          target="_blank"
          className="inline-flex items-center gap-3 bg-black/40 border border-white/5 px-10 py-5 text-gold font-bold text-[11px] tracking-[0.4em] uppercase hover:bg-gold hover:text-black transition-all group"
        >
          <Instagram size={20} className="group-hover:scale-110 transition-transform" />
          Siga @aurumlegacydetail
        </a>
      </div>
    </section>
  );
};

