  const pages = [];
  for (let i = 0; i < items.length; i += itemsPerPage) {
    pages.push(items.slice(i, i + itemsPerPage));
  }

  const handleScroll = () => {
    if (scrollRef.current) {
      const scrollLeft = scrollRef.current.scrollLeft;
      const width = scrollRef.current.offsetWidth;
      if (width > 0) {
        const newPage = Math.round(scrollLeft / width);
        setCurrentPage(newPage);
      }
    }
  };

  const scrollToPage = (pageIdx: number) => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({
        left: scrollRef.current.offsetWidth * pageIdx,
        behavior: 'smooth'
      });
    }
  };

  return (
    <section id="gallery" className="py-16 md:py-24 bg-[#050505] overflow-hidden">
      <div className="container mx-auto px-6 text-center mb-12 md:mb-16">
        <h3 className="text-gold font-bold tracking-[0.4em] mb-4 uppercase text-[9px] md:text-[10px]">Portfólio</h3>
        <h2 className="text-3xl md:text-6xl font-bold font-gold mb-6 text-white uppercase tracking-tight">Galeria de Resultados</h2>
        <div className="w-16 md:w-24 h-[2px] bg-gold-gradient mx-auto"></div>
      </div>

      {!isExpanded ? (
        /* VISTA INICIAL: Apenas 3 itens adaptados para mobile */
        <div className="container mx-auto px-6">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 md:gap-6">
            {items.slice(0, 3).map((item, idx) => (
              <div key={idx} className="h-[250px] md:h-[400px]">
                <GalleryItem item={item} />
              </div>
            ))}
          </div>
          <div className="mt-10 md:mt-12 text-center">
            <button 
              onClick={() => setIsExpanded(true)}
              className="px-8 md:px-12 py-4 md:py-5 border border-gold/30 text-gold font-bold text-[10px] md:text-[11px] tracking-[0.3em] md:tracking-[0.4em] uppercase hover:bg-gold hover:text-black transition-all"
            >
              Ver Mais Resultados
            </button>
          </div>
        </div>
      ) : (
        /* VISTA EXPANDIDA: Slider de Grids 3x3 */
        <div className="relative group/gallery">
          {/* Scroll Container */}
          <div 
            ref={scrollRef}
            onScroll={handleScroll}
            className="flex overflow-x-auto snap-x snap-mandatory hide-scrollbar cursor-grab active:cursor-grabbing"
            style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}
          >
            {pages.map((pageItems, pageIdx) => (
              <div 
                key={pageIdx} 
                className="min-w-full snap-start px-4 md:px-6"
              >
                {/* Grid 3x3 fixo mesmo no mobile */}
                <div className="grid grid-cols-3 gap-2 md:gap-4 max-w-7xl mx-auto">
                  {pageItems.map((item, idx) => (
                    <div key={idx} className="aspect-square md:h-[350px]">
                      <GalleryItem item={item} />
                    </div>
                  ))}
                </div>
              </div>
            ))}
          </div>

          {/* Paginação (Dots) */}
          <div className="flex justify-center items-center gap-2 md:gap-3 mt-8 md:mt-12">
            {pages.map((_, idx) => (
              <button
                key={idx}
                onClick={() => scrollToPage(idx)}
                className={`w-1.5 h-1.5 md:w-2 md:h-2 rounded-full transition-all duration-300 ${currentPage === idx ? 'bg-gold w-6 md:w-8' : 'bg-white/20 hover:bg-white/40'}`}
              />
            ))}
          </div>

          {/* Botão para Retornar */}
          <div className="mt-8 md:mt-12 text-center">
            <button 
              onClick={() => {
                setIsExpanded(false);
                setTimeout(() => {
                    document.getElementById('gallery')?.scrollIntoView({ behavior: 'smooth' });
                }, 100);
              }}
              className="text-gray-500 hover:text-white text-[9px] md:text-[10px] font-bold tracking-[0.3em] uppercase transition-colors"
            >
              Recolher Galeria
            </button>
          </div>

          {/* Instruções visuais de arraste para desktop */}
          <button 
            onClick={() => scrollToPage(Math.max(0, currentPage - 1))}
            className="absolute top-1/2 left-4 -translate-y-1/2 opacity-0 lg:group-hover/gallery:opacity-40 hover:!opacity-100 transition-opacity text-white pointer-events-auto hidden lg:block"
          >
             <ChevronLeft size={50} />
          </button>
          <button 
            onClick={() => scrollToPage(Math.min(pages.length - 1, currentPage + 1))}
            className="absolute top-1/2 right-4 -translate-y-1/2 opacity-0 lg:group-hover/gallery:opacity-40 hover:!opacity-100 transition-opacity text-white pointer-events-auto hidden lg:block"
          >
             <ChevronRight size={50} />
          </button>
        </div>
      )}

      <div className="mt-12 md:mt-16 text-center px-6">
        <a 
          href={`https://instagram.com/${INSTAGRAM.replace('@', '')}`}
          target="_blank"
          className="inline-flex items-center gap-3 bg-black/40 border border-white/5 px-6 md:px-10 py-4 md:py-5 text-gold font-bold text-[10px] md:text-[11px] tracking-[0.3em] md:tracking-[0.4em] uppercase hover:bg-gold hover:text-black transition-all group"
        >
          <Instagram size={18} className="group-hover:scale-110 transition-transform" />
          Siga @aurumlegacydetail
        </a>
      </div>
    </section>
