import React, { useState, useMemo } from 'react';
import { Quote, Star, MessageSquarePlus, ChevronDown, ChevronUp, User } from 'lucide-react';
import { TESTIMONIALS } from '../constants';
import { Testimonial } from '../types';

const Testimonials: React.FC = () => {
  const [userTestimonials, setUserTestimonials] = useState<Testimonial[]>([]);
  const [isExpanded, setIsExpanded] = useState(false);
  const [activeFilter, setActiveFilter] = useState<number | null>(null);

  // Form State
  const [formData, setFormData] = useState({
    name: '',
    car: '',
    text: '',
    rating: 5
  });
  const [showForm, setShowForm] = useState(false);

  const allTestimonials = useMemo(() => {
    return [...userTestimonials, ...TESTIMONIALS];
  }, [userTestimonials]);

  const filteredTestimonials = useMemo(() => {
    let list = activeFilter 
      ? allTestimonials.filter(t => t.rating === activeFilter)
      : allTestimonials;

    return isExpanded ? list : list.slice(0, 3);
  }, [allTestimonials, activeFilter, isExpanded]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.car || !formData.text) return;

    const newComment: Testimonial = {
      id: Date.now(),
      name: formData.name,
      role: formData.car,
      text: formData.text,
      rating: formData.rating
    };

    setUserTestimonials([newComment, ...userTestimonials]);
    setFormData({ name: '', car: '', text: '', rating: 5 });
    setShowForm(false);
  };

  const StarRating = ({ rating, interactive = false, onRate }: { rating: number, interactive?: boolean, onRate?: (r: number) => void }) => (
    <div className="flex gap-1">
      {[1, 2, 3, 4, 5].map((s) => (
        <Star 
          key={s} 
          size={14} 
          onClick={() => interactive && onRate?.(s)}
          className={`${s <= rating ? 'text-gold fill-gold' : 'text-gray-600'} ${interactive ? 'cursor-pointer hover:scale-125 transition-transform' : ''}`} 
        />
      ))}
    </div>
  );

  return (
    <section className="py-24 bg-[#0a0a0a]">
      <div className="container mx-auto px-6">
        <div className="text-center mb-16">
          <h3 className="text-gold font-bold tracking-[0.2em] mb-4 uppercase text-[10px]">Experiência do Cliente</h3>
          <h2 className="text-3xl md:text-5xl font-bold font-gold mb-8 uppercase tracking-tight">Quem já viveu o Legado</h2>
          <div className="w-24 h-1 bg-gold-gradient mx-auto mb-16"></div>

          {/* Filtros Centralizados e Responsivos */}
          <div className="flex flex-col items-center gap-8 mb-12">
            <button 
              onClick={() => setActiveFilter(null)}
              className={`text-[11px] font-bold tracking-[0.5em] uppercase transition-all duration-300 ${activeFilter === null ? 'text-gold' : 'text-white/40 hover:text-white'}`}
            >
              Todos os Depoimentos
            </button>

            {/* Grid de Filtros de Estrelas - Centralizado */}
            <div className="grid grid-cols-3 md:flex md:flex-row gap-2 md:gap-4 w-full max-w-4xl justify-center items-center">
              {[5, 4, 3, 2, 1].map(star => (
                <button 
                  key={star}
                  onClick={() => setActiveFilter(star)}
                  className={`
                    flex items-center justify-center gap-2 md:gap-3 py-4 md:py-6 md:px-8 transition-all duration-500 border border-transparent
                    ${activeFilter === star 
                      ? 'bg-gold-gradient text-black scale-105 shadow-[0_0_20px_rgba(212,175,55,0.2)]' 
                      : 'bg-white/5 text-white/70 hover:bg-white/10 hover:border-white/10'
                    }
                  `}
                >
                  <span className="font-bold text-base md:text-lg">{star}</span>
                  <Star size={16} className={`md:w-5 md:h-5 ${activeFilter === star ? 'fill-current' : 'text-gold/50'}`} />
                </button>
              ))}
            </div>
          </div>
        </div>

        {/* Action Buttons */}
        <div className="flex justify-center mb-16">
          <button 
            onClick={() => setShowForm(!showForm)}
            className="flex items-center gap-3 bg-black border border-gold/30 px-8 py-4 text-gold font-bold text-[10px] tracking-widest uppercase hover:bg-gold/10 transition-all"
          >
            <MessageSquarePlus size={18} />
            {showForm ? 'Fechar Formulário' : 'Avaliar o Studio'}
          </button>
        </div>

        {/* New Comment Form */}
        {showForm && (
          <div className="max-w-2xl mx-auto mb-16 p-6 md:p-10 bg-[#111] border border-gold/20 animate-in fade-in slide-in-from-top-4">
            <h4 className="text-white font-gold text-xl mb-6 text-center uppercase tracking-widest">Seu Padrão Ouro</h4>
            <form onSubmit={handleSubmit} className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <input 
                  type="text" 
                  placeholder="Nome Completo" 
                  className="bg-black border border-white/10 p-4 text-white outline-none focus:border-gold transition-colors text-sm"
                  value={formData.name}
                  onChange={e => setFormData({...formData, name: e.target.value})}
                  required
                />
                <input 
                  type="text" 
                  placeholder="Modelo do Carro" 
                  className="bg-black border border-white/10 p-4 text-white outline-none focus:border-gold transition-colors text-sm"
                  value={formData.car}
                  onChange={e => setFormData({...formData, car: e.target.value})}
                  required
                />
              </div>
              <div className="flex flex-col items-center gap-3 bg-black/40 p-4 border border-white/5">
                <span className="text-[10px] text-gray-500 uppercase tracking-widest">Sua Nota Aurum</span>
                <StarRating rating={formData.rating} interactive onRate={(r) => setFormData({...formData, rating: r})} />
              </div>
              <textarea 
                placeholder="Descreva o resultado..." 
                rows={4}
                className="w-full bg-black border border-white/10 p-4 text-white outline-none focus:border-gold transition-colors text-sm resize-none"
                value={formData.text}
                onChange={e => setFormData({...formData, text: e.target.value})}
                required
              ></textarea>
              <button 
                type="submit"
                className="w-full bg-gold-gradient text-black font-bold py-4 text-xs tracking-[0.3em] uppercase hover:brightness-110 transition-all"
              >
                Registrar no Legado
              </button>
            </form>
          </div>
        )}

        {/* Testimonials Grid */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 md:gap-8 mb-16">
          {filteredTestimonials.length > 0 ? filteredTestimonials.map((t) => (
            <div key={t.id} className="p-8 bg-[#111] border border-white/5 relative group hover:border-gold/20 transition-all duration-500 flex flex-col h-full">
              <Quote className="absolute top-4 right-4 text-gold/5 group-hover:text-gold/20 transition-colors" size={40} />

              <div className="mb-6">
                <StarRating rating={t.rating} />
              </div>

              <p className="text-gray-400 italic leading-relaxed mb-8 flex-grow text-sm">"{t.text}"</p>

              <div className="flex items-center gap-4 mt-auto pt-6 border-t border-white/5">
                {t.avatar ? (
                  <img src={t.avatar} alt={t.name} className="w-10 h-10 rounded-full border border-gold/40 object-cover" />
                ) : (
                  <div className="w-10 h-10 rounded-full border border-gold/40 flex items-center justify-center bg-black">
                    <User size={18} className="text-gold/60" />
                  </div>
                )}
                <div>
                  <h4 className="font-bold text-white text-[13px] uppercase tracking-tight">{t.name}</h4>
                  <p className="text-gold text-[9px] tracking-widest uppercase">{t.role}</p>
                </div>
              </div>
            </div>
          )) : (
            <div className="col-span-full py-20 text-center border border-white/5 border-dashed rounded-sm">
              <p className="text-gray-500 font-gold italic uppercase tracking-widest text-xs">Nenhum depoimento com {activeFilter} estrelas.</p>
            </div>
          )}
        </div>

        {/* View More Button */}
        {allTestimonials.length > 3 && (
          <div className="flex justify-center">
            <button 
              onClick={() => setIsExpanded(!isExpanded)}
              className="group flex flex-col items-center gap-2 text-gold text-[9px] font-bold tracking-[0.4em] uppercase transition-all"
            >
              <span>{isExpanded ? 'Recolher' : 'Ver mais experiências'}</span>
              <div className="mt-2 text-gold/40 group-hover:text-gold transition-transform duration-300">
                {isExpanded ? <ChevronUp size={20} /> : <ChevronDown size={20} className="animate-bounce" />}
              </div>
            </button>
          </div>
        )}
      </div>
    </section>
  );
};

export default Testimonials;

