import React, { useState } from 'react';
import { Star, MessageSquarePlus, Send } from 'lucide-react';
import { PHONE_NUMBER } from '../constants';

const Testimonials: React.FC = () => {
  const [formData, setFormData] = useState({
    name: '',
    car: '',
    text: '',
    rating: 5
  });
  const [submitted, setSubmitted] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.car || !formData.text) return;

    // Simulação de envio ou redirecionamento para o WhatsApp com o depoimento
    const message = encodeURIComponent(
      `*Novo Depoimento - MF Aurum Legacy*\n\n` +
      `*Nome:* ${formData.name}\n` +
      `*Veículo:* ${formData.car}\n` +
      `*Nota:* ${formData.rating} Estrelas\n` +
      `*Relato:* ${formData.text}`
    );

    window.open(`https://wa.me/${PHONE_NUMBER}?text=${message}`, '_blank');
    setSubmitted(true);
    setFormData({ name: '', car: '', text: '', rating: 5 });

    setTimeout(() => setSubmitted(false), 5000);
  };

  const StarRating = ({ rating, interactive = false, onRate }: { rating: number, interactive?: boolean, onRate?: (r: number) => void }) => (
    <div className="flex gap-2">
      {[1, 2, 3, 4, 5].map((s) => (
        <Star 
          key={s} 
          size={20} 
          onClick={() => interactive && onRate?.(s)}
          className={`${s <= rating ? 'text-gold fill-gold' : 'text-gray-600'} ${interactive ? 'cursor-pointer hover:scale-125 transition-transform' : ''}`} 
        />
      ))}
    </div>
  );

  return (
    <section className="py-24 bg-[#0a0a0a] border-t border-white/5">
      <div className="container mx-auto px-6">
        <div className="text-center mb-16">
          <h3 className="text-gold font-bold tracking-[0.2em] mb-4 uppercase text-[10px]">Feedback</h3>
          <h2 className="text-3xl md:text-5xl font-bold font-gold mb-8 uppercase tracking-tight">Avaliar o Studio</h2>
          <div className="w-24 h-1 bg-gold-gradient mx-auto mb-8"></div>
          <p className="text-gray-400 text-sm md:text-base max-w-xl mx-auto font-light leading-relaxed">
            Sua opinião é fundamental para mantermos o nosso Padrão Ouro de excelência. Compartilhe sua experiência conosco.
          </p>
        </div>

        {/* Form Box - Somente o formulário conforme solicitado */}
        <div className="max-w-2xl mx-auto p-8 md:p-12 bg-black border border-gold/20 relative shadow-[0_0_50px_rgba(212,175,55,0.05)]">
          <div className="absolute top-0 right-0 p-4 opacity-5">
            <MessageSquarePlus size={80} className="text-gold" />
          </div>

          {submitted ? (
            <div className="text-center py-12 animate-in fade-in zoom-in">
              <div className="w-16 h-16 bg-gold/10 rounded-full flex items-center justify-center mx-auto mb-6">
                <Star className="text-gold fill-gold" size={32} />
              </div>
              <h4 className="text-white font-gold text-2xl mb-4">Depoimento Enviado!</h4>
              <p className="text-gray-400 text-sm">Obrigado por fazer parte do legado da MF Aurum.</p>
            </div>
          ) : (
            <form onSubmit={handleSubmit} className="space-y-8 relative z-10">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[10px] text-gray-500 uppercase tracking-widest ml-1">Seu Nome</label>
                  <input 
                    type="text" 
                    placeholder="Ex: João Silva" 
                    className="w-full bg-[#0a0a0a] border border-white/10 p-4 text-white outline-none focus:border-gold transition-colors text-sm"
                    value={formData.name}
                    onChange={e => setFormData({...formData, name: e.target.value})}
                    required
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] text-gray-500 uppercase tracking-widest ml-1">Veículo</label>
                  <input 
                    type="text" 
                    placeholder="Ex: BMW M3" 
                    className="w-full bg-[#0a0a0a] border border-white/10 p-4 text-white outline-none focus:border-gold transition-colors text-sm"
                    value={formData.car}
                    onChange={e => setFormData({...formData, car: e.target.value})}
                    required
                  />
                </div>
              </div>

              <div className="flex flex-col items-center gap-4 py-6 bg-white/[0.02] border border-white/5">
                <span className="text-[10px] text-gray-500 uppercase tracking-widest">Sua Nota Aurum</span>
                <StarRating rating={formData.rating} interactive onRate={(r) => setFormData({...formData, rating: r})} />
              </div>

              <div className="space-y-2">
                <label className="text-[10px] text-gray-500 uppercase tracking-widest ml-1">Sua Experiência</label>
                <textarea 
                  placeholder="Conte-nos sobre o resultado do serviço..." 
                  rows={4}
                  className="w-full bg-[#0a0a0a] border border-white/10 p-4 text-white outline-none focus:border-gold transition-colors text-sm resize-none"
                  value={formData.text}
                  onChange={e => setFormData({...formData, text: e.target.value})}
                  required
                ></textarea>
              </div>

              <button 
                type="submit"
                className="w-full bg-gold-gradient text-black font-black py-5 text-[10px] md:text-xs tracking-[0.3em] uppercase hover:brightness-110 transition-all flex items-center justify-center gap-3"
              >
                Enviar Avaliação <Send size={16} />
              </button>
            </form>
          )}
        </div>
      </div>
    </section>
  );
};

export default Testimonials;

