import { CheckCircle2, ChevronLeft, ChevronRight } from 'lucide-react';
import { SERVICES, COMBOS, PHONE_NUMBER } from '../constants';

const Services: React.FC = () => {
  const scrollRef = useRef<HTMLDivElement>(null);
  const [activeIdx, setActiveIdx] = useState(0);

  const handleScroll = () => {
    if (scrollRef.current) {
      const scrollLeft = scrollRef.current.scrollLeft;
      const width = scrollRef.current.offsetWidth;
      const index = Math.round(scrollLeft / (width * 0.85)); 
      setActiveIdx(index);
    }
  };

  const getComboMessage = (comboName: string) => {
    return encodeURIComponent(
      `⚜️ *INTERESSE EM COMBO EXCLUSIVO* ⚜️\n\n` +
      `Olá! Fiquei impressionado com o pacote *${comboName}* no site.\n\n` +
      `Gostaria de entender melhor como esse tratamento pode elevar o padrão de conservação do meu veículo. Aguardo um especialista.`
    );
  };

  const scrollTo = (direction: 'left' | 'right') => {
    if (scrollRef.current) {
      const { scrollLeft, offsetWidth } = scrollRef.current;
      const scrollAmount = offsetWidth * 0.8;
      scrollRef.current.scrollTo({
        left: direction === 'left' ? scrollLeft - scrollAmount : scrollLeft + scrollAmount,
        behavior: 'smooth'
      });
    }
  };

  const scrollToDot = (index: number) => {
    if (scrollRef.current) {
      const width = scrollRef.current.offsetWidth;
      scrollRef.current.scrollTo({
        left: (width * 0.85) * index,
        behavior: 'smooth'
      });
    }
  };

  return (
    <section id="services" className="py-24 md:py-32 bg-[#050505]">
      <div className="container mx-auto px-6 mb-32">
        <div className="text-center mb-16 md:mb-20">
          <h3 className="text-gold font-gold text-[10px] md:text-sm tracking-[0.4em] mb-4 uppercase">Expertise Aurum</h3>
          <h2 className="text-3xl md:text-6xl font-bold font-gold mb-6 text-white uppercase tracking-tight italic">Tratamentos de Detalhamento</h2>
          <div className="w-16 md:w-24 h-[1px] bg-gold/30 mx-auto"></div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-x-12 gap-y-16">
          {SERVICES.map((s) => (
            <div key={s.id} className="group border-l border-white/5 pl-8 py-2 hover:border-gold transition-all duration-500">
              <div className="flex flex-col gap-4 mb-4">
                <div className="text-gold/50 group-hover:text-gold transition-colors">
                  <s.icon size={28} strokeWidth={1} />
                </div>
                <h4 className="text-lg md:text-xl font-bold font-gold text-white group-hover:tracking-wider transition-all uppercase tracking-tight">{s.title}</h4>
              </div>
              <p className="text-gray-500 font-light leading-relaxed text-sm group-hover:text-gray-300 transition-colors">
                {s.description}
              </p>
            </div>
          ))}
        </div>
      </div>

      <div className="bg-[#080808] py-24 md:py-32 border-y border-white/5 relative overflow-hidden">
        <div className="container mx-auto px-6 relative">
          <div className="text-center mb-16">
            <h3 className="text-gold font-gold text-[10px] md:text-sm tracking-[0.4em] mb-4 uppercase">Portfolio de Pacotes</h3>
            <h2 className="text-3xl md:text-5xl font-bold font-gold mb-6 text-white uppercase tracking-tight">Experiências Customizadas</h2>
          </div>

          <div className="relative group/combos">
            <div 
              ref={scrollRef}
              onScroll={handleScroll}
              className="flex overflow-x-auto snap-x snap-mandatory hide-scrollbar gap-8 pb-12 -mx-4 px-4 scroll-smooth"
            >
              {COMBOS.map((combo) => (
                <div 
                  key={combo.id} 
                  className="min-w-[85%] md:min-w-[45%] lg:min-w-[31%] snap-center"
                >
                  <div className={`relative p-8 md:p-14 bg-black border border-white/5 hover:border-gold/30 transition-all duration-700 flex flex-col h-full shadow-2xl ${combo.id === 'legacy' ? 'ring-1 ring-gold/20' : ''}`}>
                    {combo.id === 'legacy' && (
                      <div className="absolute -top-3 left-1/2 -translate-x-1/2 bg-gold-gradient text-black text-[8px] font-black px-6 py-1 tracking-[0.4em] uppercase whitespace-nowrap z-10">
                        O Padrão Ouro
                      </div>
                    )}
                    <div className="mb-10">
                      <h5 className="text-gold/60 text-[8px] font-bold tracking-[0.5em] uppercase mb-3">{combo.tagline}</h5>
                      <h4 className="text-2xl md:text-4xl font-bold font-gold text-white leading-none">{combo.name}</h4>
                    </div>

                    <div className="space-y-5 mb-12 flex-grow">
                      {combo.features.map((feat, i) => (
                        <div key={i} className="flex items-center gap-4 text-xs md:text-sm text-gray-400 border-b border-white/[0.03] pb-3">
                          <div className="w-1.5 h-1.5 rounded-full bg-gold/40"></div>
                          <span className="font-light tracking-wide">{feat}</span>
                        </div>
                      ))}
                    </div>

                    <a 
                      href={`https://wa.me/${PHONE_NUMBER}?text=${getComboMessage(combo.name)}`}
                      target="_blank"
                      className={`block text-center py-5 font-bold text-[10px] tracking-[0.4em] uppercase transition-all duration-500 ${combo.id === 'legacy' ? 'bg-gold-gradient text-black hover:scale-105 hover:shadow-[0_0_40px_rgba(212,175,55,0.2)]' : 'border border-gold/40 text-gold hover:bg-gold hover:text-black'}`}
                    >
                      SOLICITAR PROPOSTA
                    </a>
                  </div>
                </div>
              ))}
            </div>

            <div className="flex justify-center items-center gap-4 mt-8">
              {COMBOS.map((_, i) => (
                <button 
                  key={i} 
                  onClick={() => scrollToDot(i)}
                  className={`h-[2px] transition-all duration-700 ${activeIdx === i ? 'bg-gold w-12' : 'bg-white/10 w-4'}`}
                />
              ))}
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Services;

